export type GeneratedWireTypeName = (typeof GENERATED_WIRE_TYPE_NAME_VALUES)[number];
export const GENERATED_WIRE_TYPE_NAMES: readonly string[] = GENERATED_WIRE_TYPE_NAME_VALUES;

function issue(
  code: GeneratedWireIssueCode,
  path: string,
  message: string,
): GeneratedWireValidationResult {
  return { valid: false, issue: { code, path, message } };
}

function isObject(value: GeneratedWireValue): value is { readonly [key: string]: GeneratedWireValue } {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function childPath(path: string, field: string): string {
  return /^[A-Za-z_$][A-Za-z0-9_$]*$/u.test(field)
    ? `${path}.${field}`
    : `${path}[${JSON.stringify(field)}]`;
}

function validateSchema(
  schema: WireSchema,
  value: GeneratedWireValue,
  path: string,
): GeneratedWireValidationResult {
  switch (schema.kind) {
    case 'boolean':
      return typeof value === 'boolean' ? { valid: true } : issue('wrong_type', path, 'expected boolean');
    case 'string':
      return typeof value === 'string' ? { valid: true } : issue('wrong_type', path, 'expected string');
    case 'number':
      if (typeof value !== 'number' || !Number.isFinite(value)) {
        return issue('wrong_type', path, 'expected finite number');
      }
      if (schema.integer && (!Number.isSafeInteger(value) || value < 0)) {
        return issue('noncanonical_number', path, 'expected non-negative safe integer');
      }
      return { valid: true };
    case 'enum':
      return typeof value === 'string' && schema.values.includes(value)
        ? { valid: true }
        : issue('unknown_variant', path, `expected one of ${schema.values.join(', ')}`);
    case 'nullable':
      return value === null ? { valid: true } : validateSchema(schema.value, value, path);
    case 'ref': {
      const target = GENERATED_WIRE_SCHEMAS[schema.name];
      return target === undefined
        ? issue('unknown_type', path, `unknown generated wire type ${schema.name}`)
        : validateSchema(target, value, path);
    }
    case 'array':
      if (!Array.isArray(value)) return issue('wrong_type', path, 'expected array');
      const arrayValue = value as readonly GeneratedWireValue[];
      for (let index = 0; index < arrayValue.length; index += 1) {
        const result = validateSchema(schema.item, arrayValue[index] ?? null, `${path}[${index}]`);
        if (!result.valid) return result;
      }
      return { valid: true };
    case 'tuple':
      if (!Array.isArray(value) || value.length !== schema.items.length) {
        return issue('wrong_type', path, `expected tuple of length ${schema.items.length}`);
      }
      const tupleValue = value as readonly GeneratedWireValue[];
      for (let index = 0; index < schema.items.length; index += 1) {
        const itemSchema = schema.items[index];
        if (itemSchema === undefined) return issue('unknown_type', path, 'missing tuple schema');
        const result = validateSchema(itemSchema, tupleValue[index] ?? null, `${path}[${index}]`);
        if (!result.valid) return result;
      }
      return { valid: true };
    case 'map':
      if (!isObject(value)) return issue('wrong_type', path, 'expected object map');
      for (const [key, entry] of Object.entries(value)) {
        const keyResult = validateSchema(schema.key, key, `${path}{key}`);
        if (!keyResult.valid) return keyResult;
        const valueResult = validateSchema(schema.value, entry, childPath(path, key));
        if (!valueResult.valid) return valueResult;
      }
      return { valid: true };
    case 'object':
      return validateObject(schema.fields, value, path);
    case 'union': {
      if (!isObject(value)) return issue('wrong_type', path, 'expected tagged object');
      const tag = value[schema.discriminant];
      if (typeof tag !== 'string' || schema.variants[tag] === undefined) {
        return issue('unknown_variant', childPath(path, schema.discriminant), 'unknown tagged-union variant');
      }
      return validateObject(
        { [schema.discriminant]: { kind: 'enum', values: [tag] }, ...schema.variants[tag] },
        value,
        path,
      );
    }
  }
}

function validateObject(
  fields: Readonly<Record<string, WireSchema>>,
  value: GeneratedWireValue,
  path: string,
): GeneratedWireValidationResult {
  if (!isObject(value)) return issue('wrong_type', path, 'expected object');
  for (const key of Object.keys(value)) {
    if (fields[key] === undefined) return issue('unknown_field', childPath(path, key), 'unknown field');
  }
  for (const [field, fieldSchema] of Object.entries(fields)) {
    if (!(field in value)) return issue('missing_field', childPath(path, field), 'missing required field');
    const result = validateSchema(fieldSchema, value[field] ?? null, childPath(path, field));
    if (!result.valid) return result;
  }
  return { valid: true };
}

export function validateGeneratedWireValue(
  typeName: string,
  value: GeneratedWireValue,
  path = '$',
): GeneratedWireValidationResult {
  const schema = GENERATED_WIRE_SCHEMAS[typeName];
  return schema === undefined
    ? issue('unknown_type', path, `unknown generated wire type ${typeName}`)
    : validateSchema(schema, value, path);
}
